def findWords(board: list[list[str]], words: list[str]) -> list[str]:
    # Build trie
    trie: dict = {}
    for w in words:
        node = trie
        for c in w:
            node = node.setdefault(c, {})
        node['$'] = w  # mark end with the word itself

    m, n = len(board), len(board[0])
    result = []

    def dfs(i, j, node):
        c = board[i][j]
        if c == '#' or c not in node: return
        nxt = node[c]
        if '$' in nxt:
            result.append(nxt.pop('$'))  # avoid duplicates
        board[i][j] = '#'
        for di, dj in ((1,0),(-1,0),(0,1),(0,-1)):
            ni, nj = i+di, j+dj
            if 0 <= ni < m and 0 <= nj < n:
                dfs(ni, nj, nxt)
        board[i][j] = c

    for i in range(m):
        for j in range(n):
            dfs(i, j, trie)
    return result
